      ]
    },
    {
      "subtask": "Apply the 'at home' availability filter",
      "atomics": [
        "Identify the filter panel or filter controls on the page",
        "Locate the 'at home' filter option among availability choices",
        "Click or toggle the 'at home' filter to activate it",
        "Observe the movie list update to reflect only 'at home' movies"
      ]
    },
    {
      "subtask": "Sort movies by most recent release date",
      "atomics": [
        "Locate the sort dropdown or sort selector control",
        "Click the sort dropdown to open the sort options menu",
        "Select 'Most Recent' or 'Release Date: Newest First' option",
        "Verify the list re-sorts with most recent films appearing first"
      ]
    },
    {
      "subtask": "Verify the final result meets all requirements",
      "atomics": [
        "Confirm all displayed movies are marked with 'at home' status",
        "Verify movies are sorted in descending chronological order by release date",
        "Record the final filtered and sorted movie list"
      ]
    }
  ],
  "global_atomics": [
    "Handle any page load delays or state transitions between filter and sort operations",
    "Ensure no conflicting filters are active other than the 'at home' filter"
  ],
  "gold_actions": {
    "global": "Execute navigation to /movies, apply filter[availability]='at_home', apply sort[release_date]='descending'.",
    "subtasks": [
      {
        "subtask": "Navigate to the movie browsing interface",
        "atomics": [
          "Send GET request to home page or click home navigation button",
          "Click 'Movies' link in main navigation menu",
          "Poll for movies container element [data-testid='movies-list'] to be visible and non-loading"
        ]
      },
      {
        "subtask": "Apply the 'at home' availability filter",
        "atomics": [
          "Query filter panel element with selector .filter-section or [data-testid='filter-panel']",
          "Find checkbox or button with aria-label or text containing 'at home'",
          "Click filter control to set state to checked or activate 'at_home' filter value",
          "Wait for list to update via API response or DOM mutation to filtered results"
        ]
      },
      {
        "subtask": "Sort movies by most recent release date",
        "atomics": [
          "Query sort dropdown element [data-testid='sort-dropdown'] or .sort-control",
          "Click dropdown to expand menu of sort options",
          "Click menu option with text 'Most Recent' or data attribute sort-value='release_date_desc'",
          "Wait for movie cards in .movie-grid to re-render in new sort order"
        ]
      },
      {
        "subtask": "Verify the final result meets all requirements",
        "atomics": [
          "Query all .movie-card elements and verify each contains attribute [data-at-home='true']",
          "Extract release_date from first 5 movie cards and verify descending numeric order",
          "Count total .movie-card elements and confirm count matches expected filtered result size"
        ]
      }
    ],
    "global_atomics": [
      "Implement exponential backoff polling for movies container visibility with 5s max timeout",
      "Clear any active filters in .active-filters before applying 'at home' filter"
    ]
  }
}
